{
  "type": "DRAG_FILL",
  "lessonText": "Engage in a fun coding challenge to reinforce your Python skills.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks to create a simple game loop.",
        "codeTemplate": "while ___:\n    print('Game is running')\n    ___ = input('Continue? (yes/no): ')\n",
        "options": ["True", "False", "yes", "no"],
        "correctAnswer": "True,no",
        "explanation": "The loop continues while the condition is True, and it stops when the user inputs 'no'."
      },
      {
        "instruction": "Complete the function to check if a number is even.",
        "codeTemplate": "def is_even(num):\n    return ___ % 2 == 0\n",
        "options": ["num", "number", "value", "x"],
        "correctAnswer": "num",
        "explanation": "The function checks if the provided number is divisible by 2."
      },
      {
        "instruction": "Fill in the blanks to create a variable for player score.",
        "codeTemplate": "player_score = ___\n",
        "options": ["0", "100", "score", "points"],
        "correctAnswer": "0",
        "explanation": "Initializing player_score to 0 sets the starting score."
      },
      {
        "instruction": "Complete the code to print a welcome message.",
        "codeTemplate": "print(___)\n",
        "options": ["'Welcome to the game!'", "'Game Over!'", "'Start Playing!'", "'Good Luck!'"],
        "correctAnswer": "'Welcome to the game!'",
        "explanation": "This line outputs a welcome message to the player."
      }
    ]
  }
}
